import styled from "styled-components";
import { Link } from "react-router-dom";
import { useState } from "react";

// Componente funcional Header
const Favoritos = () => {
  return(
    <Title>Favoritos</Title>
  );
};



// Styled-Components
const Title = styled.span`
    color: rgb(255, 0, 0);
    font-size: 18px;
    letter-spacing: 1px;
    line-height: 1.08;
    padding: 1px 0;
    white-space: nowrap;
    position: relative;
`;

export default Favoritos;
